#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
typedef long long LL;
namespace IO
{
	inline int read()
	{
		int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
		while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
	}
	inline void p(int k){if(k>9)p(k/10);putchar(k%10+'0');}
	inline void print(int k,char ch){p(k);putchar(ch);}
}
using IO::read;using IO::print;
const int Mod=998244353,N=(1<<21)+10,G=3,IG=332748118;
int n,m,ps[N];LL f[N],g[N];
inline LL qpow(int a,int b=Mod-2)
	{int res=1;while(b){b&1?res=1ll*res*a%Mod:0;a=1ll*a*a%Mod;b=b>>1;}return res;}
inline void NTT(LL *f,bool typ)
{
	rep(0,n-1,i)if(i<ps[i]){LL tmp=f[i];f[i]=f[ps[i]];f[ps[i]]=tmp;}
//	rep(0,n-1,i)printf("%lld ",f[i]);puts("ff");
	for(int len=2;len<=n;len=len<<1)
	{
		int qn=len>>1,Bs=qpow(typ?G:IG,(Mod-1)/len);
		for(int k=0;k<n;k+=len)
		{
			LL buf=1;rep(k,k+qn-1,i)
			{
				int tmp=buf*f[qn+i]%Mod;f[qn+i]=(f[i]-tmp+Mod);f[qn+i]>Mod?f[qn+i]-=Mod:0; 
				f[i]+=tmp;f[i]>Mod?f[i]-=Mod:0;buf=buf*Bs%Mod;
			}
		}
	}
}
int main()
{
	n=read();m=read();rep(0,n,i)f[i]=read();rep(0,m,i)g[i]=read();
	m+=n+2;n=1;while(n<m)n=n<<1;rep(0,n-1,i)ps[i]=(ps[i>>1]>>1)|((i&1)?n>>1:0);
	NTT(f,1);NTT(g,1);rep(0,n-1,i)(f[i]*=g[i])%=Mod;NTT(f,0);
	int inv=qpow(n);rep(0,m-2,i)print(f[i]*inv%Mod,' ');
}
